import React, { useState, useRef, useEffect } from 'react';

function Header() {
  const [activeDropdown, setActiveDropdown] = useState(null);
  const headerRef = useRef(null);

  useEffect(() => {
    function onDocumentClick(e) {
      if (headerRef.current && !headerRef.current.contains(e.target)) {
        setActiveDropdown(null);
      }
    }

    document.addEventListener('mousedown', onDocumentClick);
    return () => document.removeEventListener('mousedown', onDocumentClick);
  }, []);

  const collections = ["Fall Collection '25", "Spring Collection '26", "Summer Collection '26"];

  return (
    <header className="main-header" ref={headerRef}>
      <div className="top-row">
        <div className="title">AURELIA</div>
        <div className="search" role="button" aria-label="Search">
          <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" aria-hidden="true">
            <circle cx="11" cy="11" r="7"></circle>
            <line x1="21" y1="21" x2="16.65" y2="16.65"></line>
          </svg>
        </div>
      </div>

      <div className="bottom-row">
        <div className="nav-item">
          <button
            className="nav-link"
            onClick={() => setActiveDropdown(activeDropdown === 'women' ? null : 'women')}
            aria-expanded={activeDropdown === 'women'}
          >
            WOMEN
          </button>
        </div>

        <div>
          <a>MEN</a>
        </div>

        <div>
          <a>ACCESSORIES</a>
        </div>
      </div>

      {activeDropdown === 'women' && (
        <div className="active-dropdown">
          <div className="active-dropdown-inner">
            <ul>
              {collections.map((c, i) => (
                <li key={i}><a href={`#${c}`} className="dropdown-item">{c}</a></li>
              ))}
            </ul>
            <div className="dropdown-viewall"><a href="#women-all">VIEW ALL</a></div>
          </div>
        </div>
      )}
    </header>
  );
}

export default Header;
